const VIEW_BOX = "47 412 186 136"

export default function SofaOverlay({ materialColor, isSelected, isHovered, onClick, onMouseEnter, onMouseLeave }) {
  return (
    <svg
      viewBox={VIEW_BOX}
      xmlns="http://www.w3.org/2000/svg"
      style={{ cursor: 'pointer', display: 'block', width: '100%', height: '100%', overflow: 'visible' }}
      onClick={onClick}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
    >
      <defs>
        <clipPath id="sofa-clip">
          {PATHS.map((d, i) => <path key={i} d={d} />)}
        </clipPath>
      </defs>

      <rect x="47" y="412" width="186" height="136" fill="transparent" clipPath="url(#sofa-clip)" />

      {isHovered && (
        <rect x="47" y="412" width="186" height="136"
          fill="rgba(255,255,255,0.35)" clipPath="url(#sofa-clip)" />
      )}

      {materialColor && materialColor !== 'transparent' && (
        <rect x="47" y="412" width="186" height="136"
          fill={materialColor} fillOpacity={0.55}
          clipPath="url(#sofa-clip)"
          style={{ mixBlendMode: 'multiply' }} />
      )}

      {isSelected && (
        <rect x="48" y="413" width="184" height="134"
          fill="none" stroke="rgba(60,120,220,0.7)" strokeWidth="2"
          clipPath="url(#sofa-clip)" />
      )}
    </svg>
  )
}
